// src/components/FormAluno.js
import React, { useState, useEffect, useRef } from 'react';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';

function FormAluno({ onNovoAluno, alunoEditando, onFimEdicao }) {
  const { token } = useAuth();
  const fileInputRef = useRef(null);

  // Campos
  const [nome, setNome] = useState('');
  const [ra, setRa] = useState('');
  const [periodoId, setPeriodoId] = useState('');
  const [usuario, setUsuario] = useState('');
  const [senha, setSenha] = useState('');
  const [role, setRole] = useState('aluno');
  const [mensagem, setMensagem] = useState('');
  const [periodos, setPeriodos] = useState([]);

  // Avatar
  const [avatarFile, setAvatarFile] = useState(null);
  const [avatarPreview, setAvatarPreview] = useState('');

  // Fetch períodos
  useEffect(() => {
    axios.get('/api/periodos', { headers: { Authorization: `Bearer ${token}` }, withCredentials: true })
      .then(res => setPeriodos(res.data))
      .catch(() => setPeriodos([]));
  }, [token]);

  // Preenche formulário
  useEffect(() => {
    if (alunoEditando) {
      setNome(alunoEditando.nome || '');
      setRa(alunoEditando.ra || '');
      setPeriodoId(String(alunoEditando.periodo_id || ''));
      setUsuario(alunoEditando.usuario || '');
      setRole(alunoEditando.role || 'aluno');
      setSenha('');
      setAvatarPreview(alunoEditando.avatar_url || '');
      setAvatarFile(null);
    } else {
      setNome(''); setRa(''); setPeriodoId('');
      setUsuario(''); setRole('aluno'); setSenha('');
      setAvatarPreview(''); setAvatarFile(null);
    }
    setMensagem('');
  }, [alunoEditando]);

  // Validações
  const validarNomeCompleto = v => v.trim().split(' ').filter(p => p.length >= 2).length >= 2;
  const validarRA = v => /^\d{1,9}$/.test(v);

  // Avatar handlers
  const handleAvatarClick = () => fileInputRef.current.click();
  const handleAvatarChange = e => {
    const file = e.target.files[0];
    if (file) {
      setAvatarFile(file);
      setAvatarPreview(URL.createObjectURL(file));
    }
  };

  const handleSubmit = async e => {
    e.preventDefault();
    setMensagem('');

    if (!validarNomeCompleto(nome)) { setMensagem('Informe o nome completo!'); return; }
    if (!validarRA(ra)) { setMensagem('RA inválido! Até 9 dígitos.'); return; }
    if (!usuario.trim()) { setMensagem('Insira um usuário!'); return; }
    if (!alunoEditando && senha.length < 4) { setMensagem('Senha com no mínimo 4 caracteres!'); return; }
    if (!periodoId) { setMensagem('Selecione um período!'); return; }

    const config = { headers: { Authorization: `Bearer ${token}` }, withCredentials: true };
    const dados = { nome, ra, periodo_id: periodoId, usuario, role };
    if (!alunoEditando) dados.senha = senha;

    try {
      let id;
      if (alunoEditando) {
        await axios.put(`/api/alunos/${alunoEditando.id}`, dados, config);
        id = alunoEditando.id;
        setMensagem('Aluno atualizado com sucesso!');
      } else {
        const res = await axios.post('/api/alunos', dados, config);
        id = res.data.id;
        setMensagem('Aluno cadastrado com sucesso!');
      }

      if (avatarFile) {
        const form = new FormData();
        form.append('avatar', avatarFile);
        await axios.post('/api/alunos/avatar', form, {
          ...config,
          headers: { ...config.headers, 'Content-Type': 'multipart/form-data' }
        });
      }

      // Reset e callbacks
      setNome(''); setRa(''); setPeriodoId('');
      setUsuario(''); setSenha(''); setRole('aluno');
      setAvatarPreview(''); setAvatarFile(null);
      onNovoAluno();
      if (alunoEditando) onFimEdicao(); else setTimeout(() => onFimEdicao && onFimEdicao(), 1500);
    } catch (err) {
      setMensagem(err.response?.data?.error || 'Erro ao salvar aluno.');
    }
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-4">
      <h2 className="text-xl font-bold">
        {alunoEditando ? 'Editar Aluno' : 'Cadastrar Novo Aluno'}
      </h2>

      {/* Avatar */}
      <div className="flex justify-center">
        <div onClick={handleAvatarClick} className="w-24 h-24 rounded-full overflow-hidden cursor-pointer">
          <img
            src={avatarPreview || '/default-avatar.png'}
            alt="Avatar"
            className="w-full h-full object-cover"
          />
        </div>
        <input
          ref={fileInputRef}
          type="file"
          accept="image/*"
          onChange={handleAvatarChange}
          className="hidden"
        />
      </div>

      {/* Campos */}
      <div>
        <label className="block mb-1">Nome Completo</label>
        <input
          className="w-full border rounded px-3 py-2"
          value={nome}
          onChange={e => setNome(e.target.value)}
          required
        />
      </div>
      <div>
        <label className="block mb-1">RA</label>
        <input
          className="w-full border rounded px-3 py-2"
          value={ra}
          onChange={e => setRa(e.target.value.replace(/\D/g, '').slice(0,9))}
          maxLength={9}
          required
        />
      </div>
      <div>
        <label className="block mb-1">Período</label>
        <select
          className="w-full border rounded px-3 py-2"
          value={periodoId}
          onChange={e => setPeriodoId(e.target.value)}
          required
        >
          <option value="">Selecione um período</option>
          {periodos.map(p => (
            <option key={p.id} value={String(p.id)}>
              {p.nome} ({p.turno})
            </option>
          ))}
        </select>
      </div>
      <div>
        <label className="block mb-1">Login</label>
        <input
          className="w-full border rounded px-3 py-2"
          value={usuario}
          onChange={e => setUsuario(e.target.value)}
          required
        />
      </div>
      <div>
        <label className="block mb-1">Senha</label>
        <input
          type="password"
          className="w-full border rounded px-3 py-2"
          value={senha}
          onChange={e => setSenha(e.target.value)}
          {...(!alunoEditando && { required: true })}
        />
      </div>
      <div>
        <label className="block mb-1">Permissão</label>
        <select
          className="w-full border rounded px-3 py-2"
          value={role}
          onChange={e => setRole(e.target.value)}
        >
          <option value="aluno">Aluno</option>
          <option value="recepcao">Recepção</option>
        </select>
      </div>

      <div className="flex items-center gap-4 mt-4">
        <button
          type="submit"
          className="bg-[#3172C0] text-white font-semibold py-2 px-6 rounded-full hover:bg-[#083A76]"
        >
          {alunoEditando ? 'Atualizar' : 'Cadastrar'}
        </button>
        {alunoEditando && (
          <button
            type="button"
            className="bg-[#DA3648] text-white font-semibold py-2 px-6 rounded-full hover:bg-[#BC3140]"
            onClick={onFimEdicao}
          >
            Cancelar
          </button>
        )}
      </div>

      {mensagem && (
        <p className={`mt-2 ${mensagem.toLowerCase().includes('sucesso') ? 'text-green-600' : 'text-red-600'}`}>{mensagem}</p>
      )}
    </form>
  );
}

export default FormAluno;
